import{_ as o,o as a,c as d,a3 as t}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Tenant API v1 — Leads","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant API v1 — Leads | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/api/tenant-v1-leads"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant API v1 — Leads | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/api/tenant-v1-leads"}]]},"headers":[],"relativePath":"api/tenant-v1-leads.md","filePath":"api/tenant-v1-leads.md","lastUpdated":1784475221000}'),s={name:"api/tenant-v1-leads.md"};function i(l,e,r,c,n,p){return a(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="tenant-api-v1-—-leads" tabindex="-1">Tenant API v1 — Leads <a class="header-anchor" href="#tenant-api-v1-—-leads" aria-label="Permalink to &quot;Tenant API v1 — Leads&quot;">​</a></h1><p>Base path: <code>/api/tenant/v1</code></p><p>Middleware: <code>auth:tenant-api</code>, <code>tenant.user</code>, <code>verified</code>, <code>module:leads</code>, plus permission middleware / policies.</p><p>Assignee scoping: without <code>leads.assign</code> (and not superadmin), list/board/stats/export only include leads where <code>assigned_to</code> is the current user.</p><h2 id="lead-stages" tabindex="-1">Lead stages <a class="header-anchor" href="#lead-stages" aria-label="Permalink to &quot;Lead stages&quot;">​</a></h2><h3 id="get-lead-stages" tabindex="-1">GET <code>/lead-stages</code> <a class="header-anchor" href="#get-lead-stages" aria-label="Permalink to &quot;GET `/lead-stages`&quot;">​</a></h3><p>Returns seeded pipeline stages for the workspace (New … Won / Lost).</p><h2 id="stats-board" tabindex="-1">Stats &amp; board <a class="header-anchor" href="#stats-board" aria-label="Permalink to &quot;Stats &amp; board&quot;">​</a></h2><h3 id="get-leads-stats" tabindex="-1">GET <code>/leads/stats</code> <a class="header-anchor" href="#get-leads-stats" aria-label="Permalink to &quot;GET `/leads/stats`&quot;">​</a></h3><p>Same filters as list (minus pagination/sort). Payload includes:</p><p><code>total_leads</code>, <code>my_leads</code>, <code>pipeline_value</code>, <code>todays_follow_ups</code>, <code>overdue_follow_ups</code>, <code>won_this_month</code>, <code>average_lead_value</code>, <code>conversion_rate</code>, <code>scope</code> (<code>org</code>|<code>mine</code>).</p><p>Pipeline / won metrics use stage <code>is_won</code> / <code>is_lost</code> flags, not lead status.</p><h3 id="get-leads-board" tabindex="-1">GET <code>/leads/board</code> <a class="header-anchor" href="#get-leads-board" aria-label="Permalink to &quot;GET `/leads/board`&quot;">​</a></h3><p>Columns per stage: <code>stage</code>, <code>lead_count</code>, <code>total_lead_value</code>, <code>leads[]</code>. Honors the same filters as list.</p><h2 id="leads-crud" tabindex="-1">Leads CRUD <a class="header-anchor" href="#leads-crud" aria-label="Permalink to &quot;Leads CRUD&quot;">​</a></h2><h3 id="get-leads" tabindex="-1">GET <code>/leads</code> <a class="header-anchor" href="#get-leads" aria-label="Permalink to &quot;GET `/leads`&quot;">​</a></h3><p>Query: <code>search</code>, <code>status</code>, <code>stage_id</code>, <code>priority</code>, <code>assigned_to</code> (<code>unassigned</code> or user id), <code>lead_value_min</code>, <code>lead_value_max</code>, <code>trashed</code>, <code>sort</code>, <code>direction</code>, <code>page</code>, <code>per_page</code>.</p><p>Status values: <code>active</code>, <code>waiting</code>, <code>on_hold</code>, <code>closed</code>, <code>archived</code>.</p><h3 id="post-leads" tabindex="-1">POST <code>/leads</code> <a class="header-anchor" href="#post-leads" aria-label="Permalink to &quot;POST `/leads`&quot;">​</a></h3><p>Body: <code>name</code> (required), <code>email</code>, <code>phone</code>, <code>company</code>, <code>job_title</code>, <code>source</code>, <code>lead_value</code> (or legacy alias <code>estimated_value</code>), <code>priority</code>, <code>status</code>, <code>stage_id</code>, <code>assigned_to</code>.</p><h3 id="get-leads-id" tabindex="-1">GET <code>/leads/{id}</code> <a class="header-anchor" href="#get-leads-id" aria-label="Permalink to &quot;GET `/leads/{id}`&quot;">​</a></h3><p>Includes stage, assignee, notes, follow-ups, activities, assignment histories. Exposes <code>converted_at</code> / <code>is_converted</code>.</p><h3 id="put-leads-id" tabindex="-1">PUT <code>/leads/{id}</code> <a class="header-anchor" href="#put-leads-id" aria-label="Permalink to &quot;PUT `/leads/{id}`&quot;">​</a></h3><p>Partial update of lead fields (including <code>stage_id</code>, <code>status</code>, <code>priority</code>, <code>lead_value</code>, <code>assigned_to</code>). Stage change does <strong>not</strong> sync status.</p><h3 id="delete-leads-id" tabindex="-1">DELETE <code>/leads/{id}</code> <a class="header-anchor" href="#delete-leads-id" aria-label="Permalink to &quot;DELETE `/leads/{id}`&quot;">​</a></h3><p>Soft delete.</p><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><h3 id="get-leads-export" tabindex="-1">GET <code>/leads/export</code> <a class="header-anchor" href="#get-leads-export" aria-label="Permalink to &quot;GET `/leads/export`&quot;">​</a></h3><p>Permission: <code>leads.export</code>.</p><p>Query: same filters as list, plus <code>format</code> = <code>csv</code> (default) or <code>xlsx</code>. Streams a download of the filtered set.</p><h2 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h2><p>Permission for all import routes: <code>leads.import</code> (+ <code>module:leads</code>).</p><p>Duplicate mode <code>update</code> also requires <code>leads.update</code>.</p><h3 id="get-leads-import-template" tabindex="-1">GET <code>/leads/import/template</code> <a class="header-anchor" href="#get-leads-import-template" aria-label="Permalink to &quot;GET `/leads/import/template`&quot;">​</a></h3><p>Query: <code>format</code> = <code>csv</code> (default) or <code>xlsx</code>. Downloads a sample template.</p><h3 id="get-leads-imports" tabindex="-1">GET <code>/leads/imports</code> <a class="header-anchor" href="#get-leads-imports" aria-label="Permalink to &quot;GET `/leads/imports`&quot;">​</a></h3><p>Paginated import history (status, user, file name, row counts, timestamps).</p><h3 id="post-leads-imports" tabindex="-1">POST <code>/leads/imports</code> <a class="header-anchor" href="#post-leads-imports" aria-label="Permalink to &quot;POST `/leads/imports`&quot;">​</a></h3><p>Multipart: <code>file</code> (CSV/XLSX). Stores the upload, returns import record + <code>context</code> (headers, sample rows, suggested mapping, fields). Status: <code>uploaded</code>.</p><h3 id="put-leads-imports-uuid" tabindex="-1">PUT <code>/leads/imports/{uuid}</code> <a class="header-anchor" href="#put-leads-imports-uuid" aria-label="Permalink to &quot;PUT `/leads/imports/{uuid}`&quot;">​</a></h3><p>Body: <code>{ &quot;mapping&quot;: { &quot;name&quot;: &quot;Name&quot;, &quot;email&quot;: &quot;Email&quot;, ... } }</code>. Status → <code>mapped</code>.</p><h3 id="put-leads-imports-uuid-options" tabindex="-1">PUT <code>/leads/imports/{uuid}/options</code> <a class="header-anchor" href="#put-leads-imports-uuid-options" aria-label="Permalink to &quot;PUT `/leads/imports/{uuid}/options`&quot;">​</a></h3><p>Body: <code>{ &quot;unique_fields&quot;: [&quot;email&quot;,&quot;phone&quot;], &quot;duplicate_mode&quot;: &quot;skip&quot;|&quot;update&quot;|&quot;keep&quot; }</code>.</p><h3 id="post-leads-imports-uuid-preview" tabindex="-1">POST <code>/leads/imports/{uuid}/preview</code> <a class="header-anchor" href="#post-leads-imports-uuid-preview" aria-label="Permalink to &quot;POST `/leads/imports/{uuid}/preview`&quot;">​</a></h3><p>Validates rows without writing leads. Returns preview counts + sample validation errors.</p><h3 id="post-leads-imports-uuid-run" tabindex="-1">POST <code>/leads/imports/{uuid}/run</code> <a class="header-anchor" href="#post-leads-imports-uuid-run" aria-label="Permalink to &quot;POST `/leads/imports/{uuid}/run`&quot;">​</a></h3><p>Queues <code>ProcessLeadImportJob</code> on the <code>imports</code> queue. Status → <code>queued</code> → <code>processing</code> → <code>completed</code>|<code>failed</code>. Poll <code>GET /leads/imports/{uuid}</code>.</p><h3 id="get-leads-imports-uuid" tabindex="-1">GET <code>/leads/imports/{uuid}</code> <a class="header-anchor" href="#get-leads-imports-uuid" aria-label="Permalink to &quot;GET `/leads/imports/{uuid}`&quot;">​</a></h3><p>Status + statistics for polling (<code>processed_rows</code> / <code>total_rows</code>, imported/updated/skipped/duplicate/failed counts).</p><h3 id="get-leads-imports-uuid-file" tabindex="-1">GET <code>/leads/imports/{uuid}/file</code> <a class="header-anchor" href="#get-leads-imports-uuid-file" aria-label="Permalink to &quot;GET `/leads/imports/{uuid}/file`&quot;">​</a></h3><p>Download the original uploaded file.</p><h3 id="get-leads-imports-uuid-failed-records" tabindex="-1">GET <code>/leads/imports/{uuid}/failed-records</code> <a class="header-anchor" href="#get-leads-imports-uuid-failed-records" aria-label="Permalink to &quot;GET `/leads/imports/{uuid}/failed-records`&quot;">​</a></h3><p>Download <code>failed_records.csv</code> (original row + reason + validation errors).</p><h3 id="get-leads-imports-uuid-error-report" tabindex="-1">GET <code>/leads/imports/{uuid}/error-report</code> <a class="header-anchor" href="#get-leads-imports-uuid-error-report" aria-label="Permalink to &quot;GET `/leads/imports/{uuid}/error-report`&quot;">​</a></h3><p>Download <code>error_report.csv</code> (technical/processing exceptions).</p><h2 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h2><h3 id="post-leads-id-assign" tabindex="-1">POST <code>/leads/{id}/assign</code> <a class="header-anchor" href="#post-leads-id-assign" aria-label="Permalink to &quot;POST `/leads/{id}/assign`&quot;">​</a></h3><p><code>{ &quot;assigned_to&quot;: number|null, &quot;reason&quot;?: string }</code> — records assignment history.</p><h3 id="post-leads-id-stage" tabindex="-1">POST <code>/leads/{id}/stage</code> <a class="header-anchor" href="#post-leads-id-stage" aria-label="Permalink to &quot;POST `/leads/{id}/stage`&quot;">​</a></h3><p><code>{ &quot;stage_id&quot;: number }</code> — updates stage only (status unchanged).</p><h3 id="post-leads-id-convert" tabindex="-1">POST <code>/leads/{id}/convert</code> <a class="header-anchor" href="#post-leads-id-convert" aria-label="Permalink to &quot;POST `/leads/{id}/convert`&quot;">​</a></h3><p>Permission: <code>leads.convert</code>.</p><p>Optional body: <code>{ &quot;notes&quot;?: string }</code>.</p><p>Stub until Contacts exist: sets <code>converted_at</code>, <code>conversion_meta</code> (includes <code>stub: true</code>), status <code>closed</code>, and a converted activity. Does not create contact records.</p><h3 id="post-leads-id-notes" tabindex="-1">POST <code>/leads/{id}/notes</code> <a class="header-anchor" href="#post-leads-id-notes" aria-label="Permalink to &quot;POST `/leads/{id}/notes`&quot;">​</a></h3><p><code>{ &quot;body&quot;: string }</code></p><h3 id="post-leads-id-follow-ups" tabindex="-1">POST <code>/leads/{id}/follow-ups</code> <a class="header-anchor" href="#post-leads-id-follow-ups" aria-label="Permalink to &quot;POST `/leads/{id}/follow-ups`&quot;">​</a></h3><p><code>{ &quot;title&quot;, &quot;due_at&quot;, &quot;notes?&quot;, &quot;assigned_to?&quot; }</code></p><h3 id="put-leads-id-follow-ups-followupid" tabindex="-1">PUT <code>/leads/{id}/follow-ups/{followUpId}</code> <a class="header-anchor" href="#put-leads-id-follow-ups-followupid" aria-label="Permalink to &quot;PUT `/leads/{id}/follow-ups/{followUpId}`&quot;">​</a></h3><p>Partial update (<code>title</code>, <code>due_at</code>, <code>notes</code>, <code>assigned_to</code>). Changing <code>due_at</code> is treated as a reschedule in the activity timeline.</p><h3 id="post-leads-id-follow-ups-followupid-complete" tabindex="-1">POST <code>/leads/{id}/follow-ups/{followUpId}/complete</code> <a class="header-anchor" href="#post-leads-id-follow-ups-followupid-complete" aria-label="Permalink to &quot;POST `/leads/{id}/follow-ups/{followUpId}/complete`&quot;">​</a></h3><p>Marks follow-up completed.</p><h3 id="get-leads-id-timeline" tabindex="-1">GET <code>/leads/{id}/timeline</code> <a class="header-anchor" href="#get-leads-id-timeline" aria-label="Permalink to &quot;GET `/leads/{id}/timeline`&quot;">​</a></h3><p>CRM activity timeline entries.</p><h3 id="get-leads-id-assignment-history" tabindex="-1">GET <code>/leads/{id}/assignment-history</code> <a class="header-anchor" href="#get-leads-id-assignment-history" aria-label="Permalink to &quot;GET `/leads/{id}/assignment-history`&quot;">​</a></h3><p>Ordered assignment change rows (<code>old_user</code>, <code>new_user</code>, <code>changed_by</code>, <code>reason</code>, timestamps).</p>',76)])])}const m=o(s,[["render",i]]);export{h as __pageData,m as default};
